const aiUsageFrequency = inputs.aiUsageFrequency;
const aiContentGenerationPercent = inputs.aiContentGenerationPercent;
const disclosureCompliance = inputs.disclosureCompliance;
const originalityContribution = inputs.originalityContribution;
const aiRefinementEffort = inputs.aiRefinementEffort;
const criticalThinkingApplication = inputs.criticalThinkingApplication;
const institutionalPolicyAwareness = inputs.institutionalPolicyAwareness;

// Start with a neutral baseline score. Higher score means higher risk.
let score = 50;

// Penalties (increase score)
// High percentage of content directly generated by AI is a significant risk factor.
score += aiContentGenerationPercent * 0.4; // Max +40 points

// Frequent AI usage across assignments increases general exposure to risk.
score += aiUsageFrequency * 0.15; // Max +15 points

// Bonuses (decrease score)
// High disclosure reduces integrity risk significantly.
score -= disclosureCompliance * 0.2; // Max -20 points

// High originality contribution ensures the student's voice and learning are central.
score -= originalityContribution * 0.25; // Max -25 points

// Significant effort in refining AI output demonstrates critical engagement.
score -= aiRefinementEffort * 1.5; // Max -15 points (0-10 scale * 1.5)

// Applying critical thinking during AI use prevents passive acceptance of output.
score -= criticalThinkingApplication * 1.5; // Max -15 points (0-10 scale * 1.5)

// Awareness of institutional policies suggests intentional adherence to rules.
score -= institutionalPolicyAwareness * 0.5; // Max -5 points (0-10 scale * 0.5)

// Cap the score between 0 and 100
score = Math.max(0, Math.min(100, Math.round(score)));

let riskCategory;
let recommendation;

if (score <= 20) {
  riskCategory = 'Very Low Risk';
  recommendation = 'Excellent responsible AI usage! Continue to maintain transparency, maximize originality, and actively engage with AI as a learning tool. You are effectively leveraging AI while upholding academic integrity.';
} else if (score <= 40) {
  riskCategory = 'Low Risk';
  recommendation = 'Good responsible AI usage. Review your practices to ensure full compliance with institutional policies and to maximize your unique contribution. Focus on critical refinement and active learning with AI.';
} else if (score <= 60) {
  riskCategory = 'Moderate Risk';
  recommendation = 'Consider reviewing your AI usage practices more closely. Focus on increasing your original thought, ensuring transparent disclosure, and investing more effort in critically refining AI-generated content. There are clear opportunities for improvement.';
} else if (score <= 80) {
  riskCategory = 'High Risk';
  recommendation = 'Your AI usage may pose significant academic integrity risks. Immediately review institutional policies and focus on drastically increasing originality, disclosure, and critical thinking. Passive use of AI at this level is concerning.';
} else {
  riskCategory = 'Critical Risk';
  recommendation = 'Immediate and comprehensive review of AI usage is essential. Your current practices carry a very high risk of academic integrity violations, potentially leading to serious consequences. Seek guidance from your institution and reassess your approach entirely.';
}

return { riskScore: score, riskCategory: riskCategory, recommendation: recommendation };
